import{_ as n,H as a,f as t,i as p}from"./chunks/framework.BHvCMIhP.js";const g=JSON.parse('{"title":"GPU 与显存心智:为什么 LLM 推理是 memory-bound","description":"","frontmatter":{},"headers":[],"relativePath":"../aiInfraLearning/02-GPU与显存心智.md","filePath":"../aiInfraLearning/02-GPU与显存心智.md","lastUpdated":1778649484000}'),e={name:"../aiInfraLearning/02-GPU与显存心智.md"};function d(l,s,o,r,i,c){return a(),t("div",null,[...s[0]||(s[0]=[p(`<h1 id="gpu-与显存心智-为什么-llm-推理是-memory-bound" tabindex="-1">GPU 与显存心智:为什么 LLM 推理是 memory-bound <a class="header-anchor" href="#gpu-与显存心智-为什么-llm-推理是-memory-bound" aria-label="Permalink to &quot;GPU 与显存心智:为什么 LLM 推理是 memory-bound&quot;">​</a></h1><p>打开 nvidia-smi 看一个 70B 推理服务,<strong>SM 利用率经常只有 30-50%,但显存被吃满</strong>。这不是程序写得差,是 LLM 推理的工作负载本来就是这样:每生成一个 token,要把整个模型权重从 HBM 读到 SM 算一遍,<strong>绝大部分时间花在搬数据,不在算</strong>。算力(FLOPS)便宜得多,<strong>显存容量和 HBM 带宽才是真正稀缺的资源</strong>。这一篇把 GPU 解剖一遍,讲清为什么 LLM 推理永远卡在 memory 这一头。</p><blockquote><p>一句话先记住:<strong>LLM 推理 decode 阶段的算术强度只有 2 FLOP/byte 左右,远低于现代 GPU 的拐点(H100 ≈ 295 FLOP/byte)——这意味着算力再大也用不上,瓶颈永远在 HBM 带宽和容量</strong>。所有推理引擎的优化(PagedAttention / Continuous Batching / 投机解码 / FP8 KV / Prefix Cache)本质都在做一件事:<strong>让有限的显存搬运更多有用的 token</strong>。</p></blockquote><hr><h2 id="一、为什么-gpu-值得单独一章" tabindex="-1">一、为什么 GPU 值得单独一章 <a class="header-anchor" href="#一、为什么-gpu-值得单独一章" aria-label="Permalink to &quot;一、为什么 GPU 值得单独一章&quot;">​</a></h2><p>CPU 工程师看 GPU 容易犯三类错:</p><ol><li><strong>以为&quot;GPU 快&quot;就是&quot;FLOPS 大&quot;</strong>——但 LLM 推理 90% 时间不在算</li><li><strong>以为&quot;显存 = 内存的更快版&quot;</strong>——但 HBM 带宽和算力的比例跟 DRAM/CPU 完全不同</li><li><strong>以为&quot;显卡分配空间和 malloc 差不多&quot;</strong>——但 KV Cache 的动态增长能在几秒内把卡撑爆</li></ol><p><strong>LLM 工程上 90% 的故障都和显存相关</strong>:OOM、KV Cache 满了、并发数上不去、首 token 慢、长 prompt 算不动。<strong>搞清楚显存和带宽,这一系列后面所有章节才有支点</strong>。</p><hr><h2 id="二、gpu-解剖-从一张-h100-说起" tabindex="-1">二、GPU 解剖:从一张 H100 说起 <a class="header-anchor" href="#二、gpu-解剖-从一张-h100-说起" aria-label="Permalink to &quot;二、GPU 解剖:从一张 H100 说起&quot;">​</a></h2><h3 id="_2-1-整体结构" tabindex="-1">2.1 整体结构 <a class="header-anchor" href="#_2-1-整体结构" aria-label="Permalink to &quot;2.1 整体结构&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    H100 SXM5 (整体)                       │</span></span>
<span class="line"><span>│                                                           │</span></span>
<span class="line"><span>│   ┌──────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│   │   SM (Streaming Multiprocessor) × 132 个         │   │</span></span>
<span class="line"><span>│   │   ┌────────────────────────────────────────────┐ │   │</span></span>
<span class="line"><span>│   │   │  一个 SM 内部:                             │ │   │</span></span>
<span class="line"><span>│   │   │   - 128 CUDA Core (FP32 通用算)            │ │   │</span></span>
<span class="line"><span>│   │   │   - 4 个 Tensor Core 单元 (矩阵乘加)       │ │   │</span></span>
<span class="line"><span>│   │   │   - 共享内存 / L1 Cache 合计 228 KB        │ │   │</span></span>
<span class="line"><span>│   │   │   - 寄存器文件 256 KB                      │ │   │</span></span>
<span class="line"><span>│   │   │   - Warp Scheduler × 4 (每 Warp 32 线程)   │ │   │</span></span>
<span class="line"><span>│   │   │   - Tensor Memory Accelerator (TMA, Hopper)│ │   │</span></span>
<span class="line"><span>│   │   └────────────────────────────────────────────┘ │   │</span></span>
<span class="line"><span>│   └──────────────────────────────────────────────────┘   │</span></span>
<span class="line"><span>│                            │                              │</span></span>
<span class="line"><span>│              ┌─────────────────────────┐                  │</span></span>
<span class="line"><span>│              │  L2 Cache (50 MB,全卡共享) │              │</span></span>
<span class="line"><span>│              └─────────────────────────┘                  │</span></span>
<span class="line"><span>│                            │                              │</span></span>
<span class="line"><span>│         ┌───────────────────────────────────┐             │</span></span>
<span class="line"><span>│         │  HBM3 (80 GB,带宽 3.35 TB/s)     │             │</span></span>
<span class="line"><span>│         │  分成多个独立通道并发访问         │             │</span></span>
<span class="line"><span>│         └───────────────────────────────────┘             │</span></span>
<span class="line"><span>│                            │                              │</span></span>
<span class="line"><span>│   NVLink 4 (900 GB/s)  ←→  其他 GPU(节点内 8 卡互联)     │</span></span>
<span class="line"><span>│   PCIe Gen5 (128 GB/s) ←→  CPU                            │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="_2-2-几个关键名词-搞清楚就够了" tabindex="-1">2.2 几个关键名词,搞清楚就够了 <a class="header-anchor" href="#_2-2-几个关键名词-搞清楚就够了" aria-label="Permalink to &quot;2.2 几个关键名词,搞清楚就够了&quot;">​</a></h3><table tabindex="0"><thead><tr><th>名词</th><th>是什么</th><th>工程上需要知道什么</th></tr></thead><tbody><tr><td><strong>SM</strong></td><td>GPU 的&quot;核&quot;,H100 有 132 个</td><td>SM 占用率(Occupancy)看是不是被任务塞满,推理时常常没塞满</td></tr><tr><td><strong>CUDA Core</strong></td><td>SM 内的 FP32 算术单元</td><td>通用计算,但 LLM 主要不靠它</td></tr><tr><td><strong>Tensor Core</strong></td><td>矩阵乘加专用单元,4×4 或 8×8 块为单位</td><td>LLM 的所有 matmul 都跑在这,<strong>FP8 算力是 FP16 的 2 倍</strong></td></tr><tr><td><strong>Warp</strong></td><td>32 个线程为一组,SIMT 一起跑</td><td>写 kernel 才关心;推理用户基本不碰</td></tr><tr><td><strong>共享内存 / L1</strong></td><td>SM 内部高速 SRAM,228 KB</td><td>FlashAttention 之所以快,就是把 attention 整块塞进共享内存</td></tr><tr><td><strong>L2 Cache</strong></td><td>全 GPU 共享 SRAM,H100 上 50 MB</td><td>多个 SM 协作时缓存中间结果;Hopper 上可以&quot;刻意保留&quot;某块</td></tr><tr><td><strong>HBM</strong></td><td>高带宽显存,80-192 GB</td><td><strong>LLM 推理的真正主战场</strong>,容量决定能放多大模型 + 多少 KV</td></tr><tr><td><strong>NVLink</strong></td><td>节点内 GPU 互联,H100 上 900 GB/s</td><td>TP / PP 跨卡通信走它,<strong>节点内 ≠ 节点间</strong></td></tr></tbody></table><h3 id="_2-3-simt-执行模型" tabindex="-1">2.3 SIMT 执行模型 <a class="header-anchor" href="#_2-3-simt-执行模型" aria-label="Permalink to &quot;2.3 SIMT 执行模型&quot;">​</a></h3><p>GPU 不是把 1 个任务跑得飞快,而是<strong>把 10 万个相同任务并行跑</strong>。CPU SIMD 是 4-16 通道,GPU SIMT 一次跑数万线程。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CPU SIMD (AVX-512):</span></span>
<span class="line"><span>   1 条 SIMD 指令 × 16 个 FP32 = 一次 16 个通道</span></span>
<span class="line"><span>   靠核数 × 频率扩展</span></span>
<span class="line"><span></span></span>
<span class="line"><span>GPU SIMT (H100):</span></span>
<span class="line"><span>   132 SM × (128 CUDA Core + 4 Tensor Core) × 数千线程</span></span>
<span class="line"><span>   靠&quot;同时塞极多任务&quot;扩展</span></span></code></pre></div><p>这就是为什么 GPU <strong>跑 matmul 飞快</strong>(一万个 (i, j) 输出并行),<strong>跑分支多的程序很慢</strong>(同一 warp 内不同线程走不同分支,串行执行)。</p><hr><h2 id="三、显存层级-从寄存器到-hbm" tabindex="-1">三、显存层级:从寄存器到 HBM <a class="header-anchor" href="#三、显存层级-从寄存器到-hbm" aria-label="Permalink to &quot;三、显存层级:从寄存器到 HBM&quot;">​</a></h2><p>显存不是单一存储,而是分了好几级,<strong>离 SM 越近越快越小</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│   寄存器 (per-thread)         ~256 KB / SM,~ns          │  ← 最快</span></span>
<span class="line"><span>│       ↕                                                  │</span></span>
<span class="line"><span>│   共享内存 / L1 (per-SM)       228 KB / SM,~10ns        │</span></span>
<span class="line"><span>│       ↕                                                  │</span></span>
<span class="line"><span>│   L2 Cache (全卡共享)          50 MB,~30ns             │</span></span>
<span class="line"><span>│       ↕                                                  │</span></span>
<span class="line"><span>│   HBM3 (全卡共享)              80 GB,~200ns,3.35 TB/s │</span></span>
<span class="line"><span>│       ↕                                                  │</span></span>
<span class="line"><span>│   NVLink 跨卡                  ~600ns,900 GB/s          │</span></span>
<span class="line"><span>│       ↕                                                  │</span></span>
<span class="line"><span>│   IB / RoCE 跨节点             ~2μs,400 Gbps           │  ← 最慢</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────┘</span></span></code></pre></div><table tabindex="0"><thead><tr><th>层</th><th>容量</th><th>延迟</th><th>带宽</th><th>谁负责放数据</th></tr></thead><tbody><tr><td>寄存器</td><td>256 KB/SM</td><td>&lt; 1ns</td><td>极高</td><td>编译器自动</td></tr><tr><td>共享内存</td><td>228 KB/SM</td><td>~10ns</td><td>高</td><td>Kernel 显式 <code>__shared__</code></td></tr><tr><td>L2</td><td>50 MB</td><td>~30ns</td><td>高</td><td>硬件自动 + Hopper 可显式</td></tr><tr><td>HBM</td><td>80-192 GB</td><td>~200ns</td><td>3-8 TB/s</td><td><code>cudaMalloc</code></td></tr><tr><td>NVLink</td><td>其他卡的 HBM</td><td>~600ns</td><td>900 GB/s</td><td>NCCL / cuMemRDMA</td></tr></tbody></table><p><strong>LLM 推理的核心矛盾</strong>:模型权重存在 HBM,每次计算要搬到 SM,<strong>HBM 带宽是天花板</strong>。FlashAttention 的核心招数就是:把 attention 中间矩阵留在共享内存里算完,<strong>永远不写回 HBM</strong>。</p><hr><h2 id="四、主流-gpu-对比表-2026-视角" tabindex="-1">四、主流 GPU 对比表(2026 视角) <a class="header-anchor" href="#四、主流-gpu-对比表-2026-视角" aria-label="Permalink to &quot;四、主流 GPU 对比表(2026 视角)&quot;">​</a></h2><p>数据来自 NVIDIA 官方 datasheet 和实测;<code>稀疏算力 = 密集 × 2</code>,以下都按密集算:</p><table tabindex="0"><thead><tr><th>GPU</th><th>架构</th><th>上市</th><th>FP16 TFLOPS</th><th>FP8 TFLOPS</th><th>HBM 容量</th><th>HBM 带宽</th><th>NVLink</th><th>TDP</th></tr></thead><tbody><tr><td><strong>A100 80GB</strong></td><td>Ampere</td><td>2020</td><td>312</td><td>—</td><td>80 GB HBM2e</td><td>2.0 TB/s</td><td>600 GB/s</td><td>400W</td></tr><tr><td><strong>H100 SXM5</strong></td><td>Hopper</td><td>2022</td><td>989</td><td>1979</td><td>80 GB HBM3</td><td>3.35 TB/s</td><td>900 GB/s</td><td>700W</td></tr><tr><td><strong>H200 SXM5</strong></td><td>Hopper</td><td>2024</td><td>989</td><td>1979</td><td>141 GB HBM3e</td><td>4.8 TB/s</td><td>900 GB/s</td><td>700W</td></tr><tr><td><strong>B100 SXM</strong></td><td>Blackwell</td><td>2025</td><td>1800</td><td>3500</td><td>192 GB HBM3e</td><td>8.0 TB/s</td><td>1.8 TB/s</td><td>700W</td></tr><tr><td><strong>B200 SXM</strong></td><td>Blackwell</td><td>2025</td><td>2250</td><td>4500</td><td>192 GB HBM3e</td><td>8.0 TB/s</td><td>1.8 TB/s</td><td>1000W</td></tr><tr><td><strong>GB200 NVL72</strong></td><td>Blackwell + Grace</td><td>2025</td><td>单卡同 B200</td><td>单卡同 B200</td><td>192 GB × 72 卡</td><td>8 TB/s</td><td>整机柜共享</td><td>整柜级</td></tr><tr><td><strong>RTX 4090</strong></td><td>Ada</td><td>2022</td><td>165</td><td>330</td><td>24 GB GDDR6X</td><td>1.0 TB/s</td><td>无</td><td>450W</td></tr><tr><td><strong>RTX 5090</strong></td><td>Blackwell</td><td>2025</td><td>209</td><td>419</td><td>32 GB GDDR7</td><td>1.79 TB/s</td><td>无</td><td>575W</td></tr></tbody></table><p><strong>怎么读这张表</strong>:</p><ol><li><strong>A100 → H100</strong>:FP16 算力 3.2x,HBM 带宽 1.7x。从 Hopper 起 <strong>FP8 落地</strong>,推理实际吞吐再 2x</li><li><strong>H100 → H200</strong>:算力不变,<strong>HBM 1.76x 容量 + 1.43x 带宽</strong>——典型为长上下文 LLM 推理服务</li><li><strong>H200 → B200</strong>:算力 2.3x,容量 1.36x,带宽 1.67x——<strong>Blackwell 把架构平衡又拉回算力一侧</strong></li><li><strong>数据中心卡 vs 消费卡</strong>:H100 vs 4090,FP16 算力 6x,HBM 容量 3.3x,<strong>带宽 3.35x</strong>——NVLink 才是真正的代差,4090 单卡只能跑小模型</li></ol><p><strong>为什么 H200 是 LLM 推理的甜点</strong>:<strong>显存大 + 带宽大,算力够用</strong>——LLM decode 反正用不满算力,容量和带宽是直接收益。一张 H200 单卡能装下 70B FP8(70 GB)+ 几十个并发的 KV,A100 装不下,H100 紧绷。</p><p><strong>B200 的意义</strong>:训练大模型(算力提升 + 显存翻倍 + NVLink 翻倍)。推理上 B200 不一定线性收益——decode 仍 memory-bound,算力的提升用不上,带宽提升才是 LLM 推理的实际收益。</p><hr><h2 id="五、roofline-模型-一张图看懂-瓶颈在哪" tabindex="-1">五、Roofline 模型:一张图看懂&quot;瓶颈在哪&quot; <a class="header-anchor" href="#五、roofline-模型-一张图看懂-瓶颈在哪" aria-label="Permalink to &quot;五、Roofline 模型:一张图看懂&quot;瓶颈在哪&quot;&quot;">​</a></h2><h3 id="_5-1-算术强度-arithmetic-intensity" tabindex="-1">5.1 算术强度 (Arithmetic Intensity) <a class="header-anchor" href="#_5-1-算术强度-arithmetic-intensity" aria-label="Permalink to &quot;5.1 算术强度 (Arithmetic Intensity)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>算术强度 = 算的次数 (FLOP) / 搬的数据量 (Byte)</span></span>
<span class="line"><span>        ≈ &quot;每搬一个字节做几次运算&quot;</span></span></code></pre></div><ul><li>矩阵乘 (matmul) M=N=K:<strong>算术强度 ≈ N</strong>(大矩阵高,小矩阵低)</li><li>Attention(Q × K^T × V):取决于 seq_len 和 batch</li><li><strong>LLM Decode 阶段每生成 1 个 token</strong>:<code>FLOP ≈ 2 × P</code>(P 是参数量),<code>Byte ≈ P × byte_per_param</code>,<strong>算术强度 ≈ 2 / byte_per_param</strong></li></ul><h3 id="_5-2-roofline-图" tabindex="-1">5.2 Roofline 图 <a class="header-anchor" href="#_5-2-roofline-图" aria-label="Permalink to &quot;5.2 Roofline 图&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>性能 (FLOP/s)</span></span>
<span class="line"><span>     ↑</span></span>
<span class="line"><span>     │</span></span>
<span class="line"><span>Peak │                       ┌─────────────────────────  Peak FLOPS 上限</span></span>
<span class="line"><span>     │                      ╱</span></span>
<span class="line"><span>     │                     ╱</span></span>
<span class="line"><span>     │                    ╱  ← Compute-bound 区</span></span>
<span class="line"><span>     │                   ╱     (算力打满)</span></span>
<span class="line"><span>     │                  ╱</span></span>
<span class="line"><span>     │                 ╱</span></span>
<span class="line"><span>     │                ╱</span></span>
<span class="line"><span>     │               ╱</span></span>
<span class="line"><span>     │              ╱</span></span>
<span class="line"><span>     │             ╱  ← Memory-bound 区</span></span>
<span class="line"><span>     │            ╱     (带宽打满)</span></span>
<span class="line"><span>     │           ╱</span></span>
<span class="line"><span>     │          ╱</span></span>
<span class="line"><span>     │         ╱</span></span>
<span class="line"><span>     │        ╱</span></span>
<span class="line"><span>     │       ╱</span></span>
<span class="line"><span>     │      ╱</span></span>
<span class="line"><span>     └─────┴────────────────────────────────────→ 算术强度 (FLOP/Byte)</span></span>
<span class="line"><span>           ↑</span></span>
<span class="line"><span>        拐点 = Peak FLOPS / HBM Bandwidth</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   H100 (FP16):  989 TFLOPS / 3.35 TB/s ≈ 295 FLOP/Byte</span></span>
<span class="line"><span>   H100 (FP8):   1979 TFLOPS / 3.35 TB/s ≈ 591 FLOP/Byte</span></span>
<span class="line"><span>   H200 (FP16):  989 TFLOPS / 4.8 TB/s ≈ 206 FLOP/Byte</span></span>
<span class="line"><span>   B200 (FP16):  2250 TFLOPS / 8.0 TB/s ≈ 281 FLOP/Byte</span></span>
<span class="line"><span>   A100 (FP16):  312 TFLOPS / 2.0 TB/s ≈ 156 FLOP/Byte</span></span></code></pre></div><p><strong>读法</strong>:横轴是任务的算术强度,纵轴是能跑出来的性能。算术强度 &lt; 拐点 → 卡在带宽上(memory-bound);&gt; 拐点 → 卡在算力上(compute-bound)。</p><h3 id="_5-3-llm-落在哪" tabindex="-1">5.3 LLM 落在哪 <a class="header-anchor" href="#_5-3-llm-落在哪" aria-label="Permalink to &quot;5.3 LLM 落在哪&quot;">​</a></h3><p>把不同工作负载标到 Roofline 上:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>工作负载                            算术强度 (FP16)    位置</span></span>
<span class="line"><span>────────────────────────────       ──────────       ────────</span></span>
<span class="line"><span>LLM Decode (batch=1)              ~ 2                极左,memory-bound</span></span>
<span class="line"><span>LLM Decode (batch=32)             ~ 64               左侧,memory-bound  </span></span>
<span class="line"><span>LLM Decode (batch=256, FP8)       ~ 256              接近拐点</span></span>
<span class="line"><span>LLM Prefill (batch=1, S=4096)     ~ 256              接近拐点</span></span>
<span class="line"><span>LLM Prefill (batch=32, S=4096)    ~ 1000             右侧,compute-bound</span></span>
<span class="line"><span>训练 forward (大 batch)            ~ 1000+            compute-bound</span></span>
<span class="line"><span>训练 backward                      ~ 500+             compute-bound</span></span>
<span class="line"><span></span></span>
<span class="line"><span>         H100 拐点 ≈ 295 FLOP/Byte (FP16)</span></span>
<span class="line"><span>                   |</span></span>
<span class="line"><span>   Decode b=1   Decode b=32  | Prefill   训练</span></span>
<span class="line"><span>       ●            ●        |   ●        ●</span></span>
<span class="line"><span>   ────●────────────●────────|───●────────●─────→</span></span>
<span class="line"><span>                             ↑</span></span>
<span class="line"><span>                          拐点</span></span></code></pre></div><p><strong>关键观察</strong>:</p><ul><li><strong>Decode batch=1 是最惨的工况</strong>——算力跑不出 1%,纯靠 HBM 带宽</li><li><strong>加大 batch 是把 decode 拖到拐点的最直接办法</strong>——同一份权重供更多请求复用,算术强度线性涨。这就是 <strong>Continuous Batching 的本质</strong>(09 篇)</li><li><strong>Prefill 天然 compute-bound</strong>——一个长 prompt 一次性算完,矩阵很大,Tensor Core 跑满</li><li><strong>FP8 把拐点右移</strong>——同样的工作负载更容易落在 memory-bound,因此 FP8 对 prefill 加速明显,对 decode 加速主要来自&quot;每参数搬运的字节少了一半&quot;</li></ul><hr><h2 id="六、显存账-llm-推理到底吃多少" tabindex="-1">六、显存账:LLM 推理到底吃多少 <a class="header-anchor" href="#六、显存账-llm-推理到底吃多少" aria-label="Permalink to &quot;六、显存账:LLM 推理到底吃多少&quot;">​</a></h2><h3 id="_6-1-一个-70b-模型推理的显存构成" tabindex="-1">6.1 一个 70B 模型推理的显存构成 <a class="header-anchor" href="#_6-1-一个-70b-模型推理的显存构成" aria-label="Permalink to &quot;6.1 一个 70B 模型推理的显存构成&quot;">​</a></h3><p>以 70B FP16 为例,单卡 H100 80GB 装不下,需要 2 张 TP 切:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>模型权重 (FP16):  70B × 2 bytes = 140 GB    跨 2 张 H100 各 70 GB</span></span>
<span class="line"><span>KV Cache (每请求每 token):</span></span>
<span class="line"><span>   每层 KV = 2 × n_head × head_dim × 2 bytes</span></span>
<span class="line"><span>   70B 类模型: 每 token KV ≈ 320 KB (FP16)</span></span>
<span class="line"><span>   </span></span>
<span class="line"><span>   单请求 4K 上下文:        320 KB × 4096 ≈ 1.3 GB</span></span>
<span class="line"><span>   并发 32 请求 × 4K:        32 × 1.3 GB ≈ 42 GB</span></span>
<span class="line"><span>   并发 32 请求 × 32K:       32 × 10.5 GB ≈ 336 GB  ← 装不下!</span></span>
<span class="line"><span></span></span>
<span class="line"><span>激活 (临时):              ~ 几 GB,通常忽略</span></span>
<span class="line"><span>Workspace / 临时 buffer:  ~ 2-4 GB</span></span></code></pre></div><p><strong>两个直觉</strong>:</p><ol><li><strong>长上下文是显存杀手</strong>——KV 随 seq_len 线性增长,32K 上下文的 KV 能占到模型本身的几倍</li><li><strong>并发数被 KV 卡住</strong>——不是 SM 不够,是 KV 装不下;<strong>这就是 PagedAttention 要解决的问题</strong>(08 篇)</li></ol><h3 id="_6-2-训练显存构成" tabindex="-1">6.2 训练显存构成 <a class="header-anchor" href="#_6-2-训练显存构成" aria-label="Permalink to &quot;6.2 训练显存构成&quot;">​</a></h3><p>同样 70B,训练显存账完全不同(03 篇展开):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>模型权重 (FP16):           140 GB</span></span>
<span class="line"><span>梯度 (FP16):               140 GB    ← 推理没有</span></span>
<span class="line"><span>优化器状态 (Adam FP32):     560 GB   ← 推理没有,Adam 是 2x params 的 momentum + variance</span></span>
<span class="line"><span>激活 (用于 backward):      取决于 batch 和 seq_len,几十到几百 GB</span></span>
<span class="line"><span>─────────────────────────────────────</span></span>
<span class="line"><span>总计:                      ~ 1 TB+   一张 80GB H100 远远装不下</span></span></code></pre></div><p><strong>这就是 ZeRO / TP / PP / FSDP 必须存在的原因</strong>——把这 1TB 切到几十张卡上去(14-18 篇)。</p><hr><h2 id="七、计算-通信-存储三角" tabindex="-1">七、计算 / 通信 / 存储三角 <a class="header-anchor" href="#七、计算-通信-存储三角" aria-label="Permalink to &quot;七、计算 / 通信 / 存储三角&quot;">​</a></h2><p>把 GPU 性能拆成三个维度,<strong>任何工作负载都卡在其中一边</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    Compute (FLOPS)</span></span>
<span class="line"><span>                          ●</span></span>
<span class="line"><span>                        ╱ │ ╲</span></span>
<span class="line"><span>                       ╱  │  ╲</span></span>
<span class="line"><span>                      ╱   │   ╲</span></span>
<span class="line"><span>                     ╱  H100  ╲</span></span>
<span class="line"><span>                    ╱     │     ╲</span></span>
<span class="line"><span>                   ╱      │      ╲</span></span>
<span class="line"><span>                  ╱       │       ╲</span></span>
<span class="line"><span>                 ●────────┴────────●</span></span>
<span class="line"><span>            Memory                Comm</span></span>
<span class="line"><span>          (HBM 带宽)              (NVLink/IB)</span></span></code></pre></div><p>不同工作负载偏向不同顶点:</p><table tabindex="0"><thead><tr><th>工作负载</th><th>算力</th><th>带宽</th><th>通信</th><th>主要瓶颈</th></tr></thead><tbody><tr><td>LLM Decode (batch 小)</td><td>5%</td><td>95%</td><td>0%</td><td>HBM 带宽</td></tr><tr><td>LLM Decode (batch 大)</td><td>50%</td><td>80%</td><td>0%</td><td>平衡偏带宽</td></tr><tr><td>LLM Prefill</td><td>80%</td><td>60%</td><td>0%</td><td>算力 (单卡)</td></tr><tr><td>训练 forward (单卡)</td><td>90%</td><td>50%</td><td>0%</td><td>算力</td></tr><tr><td>训练 backward (单卡)</td><td>70%</td><td>60%</td><td>0%</td><td>算力</td></tr><tr><td>多卡训练 AllReduce</td><td>30%</td><td>30%</td><td>90%</td><td>通信</td></tr><tr><td>Pipeline 并行</td><td>50%</td><td>30%</td><td>70%</td><td>通信 + 气泡</td></tr></tbody></table><p><strong>LLM 工程的全部就是在这个三角里挪位置</strong>:</p><ul><li>vLLM 把 decode 从 batch=1 的极端 memory-bound 拖到大 batch 的&quot;还算合理&quot;</li><li>TP 把单卡 OOM 摊到多卡,代价是 AllReduce 通信</li><li>FP8 把所有顶点都向&quot;更便宜&quot;侧推一格(参数小一半 + 算力翻倍)</li><li>投机解码把 decode 的 memory-bound 偷换成&quot;少跑几次 decode&quot;(11 篇)</li></ul><hr><h2 id="八、cpu-心智-vs-gpu-心智-别串" tabindex="-1">八、CPU 心智 vs GPU 心智:别串 <a class="header-anchor" href="#八、cpu-心智-vs-gpu-心智-别串" aria-label="Permalink to &quot;八、CPU 心智 vs GPU 心智:别串&quot;">​</a></h2><p>很多坑就是用 CPU 直觉套 GPU:</p><table tabindex="0"><thead><tr><th>直觉</th><th>CPU 上</th><th>GPU 上</th><th>后果</th></tr></thead><tbody><tr><td>&quot;加更多核就更快&quot;</td><td>大致成立</td><td>错——SM 已经够多,问题在喂得起</td><td>加 GPU 没用,SM 利用率仍低</td></tr><tr><td>&quot;分配内存是 O(1)&quot;</td><td>成立</td><td>错——<code>cudaMalloc</code> 慢且影响 stream</td><td>频繁 alloc 拖垮服务</td></tr><tr><td>&quot;分支随便写&quot;</td><td>成立</td><td>错——Warp 内分支串行</td><td>If 多的 kernel 慢得不可理喻</td></tr><tr><td>&quot;小数据并发好&quot;</td><td>成立</td><td>错——小矩阵跑不满 SM</td><td>batch=1 永远跑不满 GPU</td></tr><tr><td>&quot;缓存命中靠 LRU&quot;</td><td>成立</td><td>部分——L2 也是 LRU,但容量太小</td><td>不能指望 70GB 模型靠 L2</td></tr><tr><td>&quot;内存够就行&quot;</td><td>成立</td><td>错——HBM 带宽决定速度</td><td>容量够但 step 时间慢</td></tr><tr><td>&quot;throughput = qps × 单次延迟&quot;</td><td>成立</td><td>错——decode 大 batch 时单次延迟和并发数解耦</td><td>容量规划算错</td></tr></tbody></table><p><strong>最重要的一条</strong>:CPU 工程师习惯把&quot;算力&quot;作为性能上限,GPU 工程师必须<strong>把&quot;HBM 带宽&quot;作为第一性能维度</strong>,FLOPS 是第二位的。</p><hr><h2 id="九、看完这一篇-你应该能" tabindex="-1">九、看完这一篇,你应该能 <a class="header-anchor" href="#九、看完这一篇-你应该能" aria-label="Permalink to &quot;九、看完这一篇,你应该能&quot;">​</a></h2><ul><li>在白板画 GPU 解剖图:SM / Tensor Core / 共享内存 / L2 / HBM / NVLink 的层级关系</li><li>默写 A100 / H100 / H200 / B200 的算力和 HBM 带宽量级,知道为什么 H200 是 LLM 推理甜点</li><li>画 Roofline 模型,说清&quot;算术强度 &lt; 拐点 = memory-bound&quot;</li><li>解释 LLM decode 为什么永远 memory-bound,batch 大了能拖到哪</li><li>算 70B 推理一个并发的 KV Cache 大约多少 MB(每 token ~320KB × seq_len)</li><li>看 nvidia-smi 知道 SM 利用率低 + 显存吃满意味着什么</li></ul><p>下一篇:<strong>03 训练与推理的根本不同</strong> — 训练有反向 + 优化器状态,推理只有前向 + KV Cache;推理还要再切 Prefill(compute-bound)vs Decode(memory-bound)两阶段。<strong>这个分界决定了后续所有优化的方向</strong>:推理优化都在解 decode 的 memory-bound,训练优化都在解显存与通信。</p>`,73)])])}const u=n(e,[["render",d]]);export{g as __pageData,u as default};
